void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
   ret = texture( sampler_rand00, vUv);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0,uTexSize.w);

dz = 0;
float dist = 1;
vec3 inten = 1;
float mask = 0;
ret1 = 0;
int anz = 4;
int n = 0; dx = 0; dy = 0;
tmp = (vUv-.5) * uAspect.xy;
while (n <= anz) {
    dist = 1-fract(.25*n+q29); //evtl sqrt !
uv2 = tmp;

    c = n%2;
    s = (n+1)%2;
    uv2.x =  tmp.x*c - tmp.y*s;
    uv2.y =  tmp.x*s + tmp.y*c;
    uv2*= uAspect.yx;
    inten.r =  sqrt(dist)*(1-dist*dist)*2;
    inten.g = 1;
    inten.b = 1;

    uv3 = 4*(uv2)*dist + .7* n + .2*q29*c;
    neu = GetPixel(uv3);

    dx = lum(GetPixel(uv3+hor)- GetPixel(uv3-hor));
    dy = lum(GetPixel(uv3+ver)- GetPixel(uv3-ver));
    dz += inten.r*vec2 (dx,dy);

   ret1 = max(ret1,neu*inten);
n++;
}

//******************

vec2 uv1 = (vUv-.5)*uAspect.xy ;
float rad2 = 6*length(uv1);
float rad1 = 1/(rad2+.1);

uv2 = vec2 (vAngle/2, rad1);
rs2 = uv2;
uv2.y = uv2.y + q30;

vec3 noise = .5;
vec3 dots = noise * rs2.y * vec3(.0,.1,.9);
dots = clamp01(dots);

rs2 = cos(uv2*4) + (ret1)*12;
dots += (.5+q22)*(1-vRadius)*clamp01(.05/length(rs2)) ;

ret = ret1*vec3(q26/2,.6,.3) - 2*ret1.r*(1-dots)
 + .4*q32*dots * clamp01(1-2*ret1.r) ;


  fragColor = ret;
}
